-- Matriz stage_templates generada desde stage_templates_revision_v3.tsv
-- Ejecutar en Postgres para crear la tabla e insertar las 76 reglas actuales.

CREATE TABLE IF NOT EXISTS stage_templates (
  id BIGSERIAL PRIMARY KEY,
  stage_actual VARCHAR(128) NOT NULL,
  posicion SMALLINT NULL,
  posibles_match TEXT NOT NULL,
  posibles_match_revisado TEXT NOT NULL,
  es_fallback BOOLEAN NOT NULL DEFAULT false,
  procesa_datos BOOLEAN NOT NULL DEFAULT false,
  dato_esperado VARCHAR(128) NULL,
  nuevo_stage VARCHAR(128) NOT NULL,
  tipo_respuesta TEXT NOT NULL,
  tipo_respuesta_revisado TEXT NOT NULL,
  activo BOOLEAN NOT NULL DEFAULT true,
  created_at TIMESTAMPTZ NOT NULL DEFAULT now(),
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_stage_templates_stage_actual ON stage_templates(stage_actual);
CREATE INDEX IF NOT EXISTS idx_stage_templates_nuevo_stage ON stage_templates(nuevo_stage);
CREATE INDEX IF NOT EXISTS idx_stage_templates_activo ON stage_templates(activo);

